@AbapCatalog.sqlViewName: 'ZV_FI_LINEITEMS'
@AbapCatalog.compiler.compareFilter: true
@AbapCatalog.preserveKey: true
define view ZI_FinanceLineItems
  as select from acdoca
{
  key rbukrs, key belnr, key gjahr, key buzei,
      racct, hsl, wsl, poper, budat
}
where rldnr = '0L'  " Leading ledger filter

@AbapCatalog.sqlViewName: 'ZV_FI_BALANCE'
@AbapCatalog.compiler.compareFilter: true
@AbapCatalog.preserveKey: true
@Analytics.dataCategory: #CUBE
define view ZI_FinanceBalance
  as select from acdoca
{
  key rbukrs,
  key gjahr,
  key racct,
      poper,
      SUM( hsl ) as Balance
}
where  rldnr = '0L'   " Leading ledger — static filter
group by rbukrs, gjahr, racct, poper

" CDS View with access control enabled:
@AccessControl.authorizationCheck: #CHECK
define view ZI_FinanceItems as select from acdoca {
  key rbukrs, key gjahr, key belnr, key buzei,
      racct, hsl
}

" DCL Role definition (ABAP Eclipse -> New -> DCL):
define role ZAccessControl_FinanceItems
  grant select on ZI_FinanceItems
    where ( rbukrs ) = aspect pfcg_auth(
      F_BKPF_BUK,    " Auth object
      BUKRS,         " Field in auth object
      ACTVT = '03'   " Display activity
    );
